udt:




































.panel-root {
    auto-size: grow;
    flow: vertical;
    gap: 8;
}

.watchlist-search {
    auto-size: grow fit;
    background-color: 0x20FFFFFF;
    border-radius: 6;
    stroke-color: 0x20FFFFFF;
    stroke-width: 1;
    stroke-inset: 1;
    stroke-radius: 4;
    padding: 8 12;
    gap: 8;
}

.search-icon {
    size: 16 16;
    anchor: middle-center;
    text-align: middle-center;
    font: 2;
    font-size: 14;
}

.search-placeholder {
    auto-size: grow fit;
    anchor: middle-left;
    font-size: 12;
}

.watchlist-items {
    auto-size: grow;
    flow: vertical;
    gap: 4;
    overflow: scroll;
}

.watchlist-row {
    flow: horizontal;
    gap: 8;
}

.watchlist-row-left {
    auto-size: grow fit;
    gap: 8;
}

.watchlist-item-icon {
    size: 32 32;
    border-radius: 4;
    anchor: middle-center;
}

.watchlist-item-info {
    auto-size: grow fit;
    flow: vertical;
    gap: 2;
    anchor: middle-left;
}

.watchlist-item-name {
    font-size: 13;
}

.watchlist-item-world {
    font-size: 10;
}

.watchlist-row-right {
    auto-size: fit;
    gap: 6;
    anchor: middle-right;
}

.watchlist-item-profit {
    font-size: 14;
    anchor: middle-right;
}

.watchlist-empty {
    auto-size: grow;
    flow: vertical;
    gap: 12;
    anchor: middle-center;
    padding: 40 0;
}

.empty-icon {
    font: 2;
    font-size: 32;
    anchor: top-center;
    text-align: middle-center;
    auto-size: grow fit;
}

.empty-text {
    font-size: 13;
    anchor: top-center;
    text-align: middle-center;
    auto-size: grow fit;
}
